import React, { Component } from 'react';
import data from './../Json/data';

const jsonData = data.resume;
class Resume extends Component {
  render() {

    if(jsonData){
      var skillmessage = jsonData.skillmessage;
      var skillmessage1 = jsonData.skillmessage1;

      var education = jsonData.education.map(function(edu){
        return (
          <div key={edu.degree} name={edu.degree} style={{ position: 'relative', marginBottom: '35px', textAlign: 'left' }}>
            {/* Timeline marker dot */}
            <div style={{
              position: 'absolute',
              left: '-32px',
              top: '6px',
              width: '14px',
              height: '14px',
              borderRadius: '50%',
              backgroundColor: '#11ABB0',
              border: '3px solid #fff',
              boxShadow: '0 2px 4px rgba(0,0,0,0.15)'
            }} />
            
            <h3 style={{ font: 'bold 18px/1.3 "opensans-bold", sans-serif', color: '#313131', margin: '0 0 6px 0' }}>
              {edu.degree}
            </h3>
            <p className="info" style={{ font: 'italic 14px/24px "librebaskerville-regular", serif', color: '#6E7881', margin: '0 0 10px 0' }}>
              <span style={{ fontWeight: 'bold', color: '#11ABB0' }}>{edu.school}</span>
              <span style={{ margin: '0 8px' }}>&bull;</span>
              <em className="date" style={{ font: 'normal 12px "opensans-regular", sans-serif', background: '#f0f4f5', padding: '3px 10px', borderRadius: '12px', color: '#526066' }}>{edu.graduated}</em>
            </p>
            <p className="text-adjust" style={{ font: '14px/1.6 "opensans-regular", sans-serif', color: '#6E7881', margin: 0 }}>
              {edu.description}
            </p>
          </div>
        )
      })
      var work = jsonData.work.map(function(work){
        return (
          <div name={work.company} key={work.company} style={{ position: 'relative', marginBottom: '35px', textAlign: 'left' }}>
            {/* Timeline marker dot */}
            <div style={{
              position: 'absolute',
              left: '-32px',
              top: '6px',
              width: '14px',
              height: '14px',
              borderRadius: '50%',
              backgroundColor: '#11ABB0',
              border: '3px solid #fff',
              boxShadow: '0 2px 4px rgba(0,0,0,0.15)'
            }} />
            
            <h3 style={{ font: 'bold 18px/1.3 "opensans-bold", sans-serif', color: '#313131', margin: '0 0 6px 0' }}>
              {work.company}
            </h3>
            <p className="info" style={{ font: 'italic 14px/24px "librebaskerville-regular", serif', color: '#6E7881', margin: '0 0 10px 0' }}>
              <span style={{ fontWeight: 'bold', color: '#11ABB0' }}>{work.title}</span>
              <span style={{ margin: '0 8px' }}>&bull;</span>
              <em className="date" style={{ font: 'normal 12px "opensans-regular", sans-serif', background: '#f0f4f5', padding: '3px 10px', borderRadius: '12px', color: '#526066' }}>{work.years}</em>
            </p>
            <p className="text-adjust" style={{ font: 'bold 14px/1.6 "opensans-regular", sans-serif', color: '#555', margin: '0 0 10px 0' }}>
              {work.description}
            </p>
            {work.activities && work.activities.length > 0 && (
              <details style={{ marginTop: '10px', marginBottom: '20px' }}>
                <summary style={{ cursor: 'pointer', outline: 'none', color: '#11ABB0', fontWeight: 'bold' }}>
                  👉 Ver Atividades / Desafios Resolvidos
                </summary>
                <ul style={{ listStyleType: 'disc', paddingLeft: '20px', marginTop: '8px' }}>
                  {work.activities.map(function(act, index){
                    return <li key={index} style={{ marginBottom: '6px', textAlign: 'left', font: '14px/1.5 "opensans-regular", sans-serif' }}>{act}</li>
                  })}
                </ul>
              </details>
            )}
          </div>
        )
      })
      var tagskills = jsonData.skills.map(function(cat){
        return (
          <div key={cat.category} style={{ marginBottom: '24px' }}>
            <h5 style={{ color: '#313131', marginBottom: '8px', textTransform: 'uppercase', fontSize: '13px', letterSpacing: '1px', fontWeight: 'bold' }}>
              {cat.category}
            </h5>
            <div>
              {cat.list.map(function(skill){
                return (
                  <div key={skill} className="chip" style={{ margin: '4px' }}>
                    <div alt={skill} className="chip-content">{skill}</div>
                  </div>
                )
              })}
            </div>
          </div>
        )
      })
      var certification = jsonData.certification.map(function(cert){
        return (
          <div key={cert.degree} name={cert.degree} style={{ position: 'relative', marginBottom: '35px', textAlign: 'left' }}>
            {/* Timeline marker dot */}
            <div style={{
              position: 'absolute',
              left: '-32px',
              top: '6px',
              width: '14px',
              height: '14px',
              borderRadius: '50%',
              backgroundColor: '#11ABB0',
              border: '3px solid #fff',
              boxShadow: '0 2px 4px rgba(0,0,0,0.15)'
            }} />
            
            <h3 style={{ font: 'bold 18px/1.3 "opensans-bold", sans-serif', color: '#313131', margin: '0 0 6px 0' }}>
              {cert.degree}
            </h3>
            <p className="info" style={{ font: 'italic 14px/24px "librebaskerville-regular", serif', color: '#6E7881', margin: '0 0 10px 0' }}>
              <span style={{ fontWeight: 'bold', color: '#11ABB0' }}>{cert.school}</span>
              <span style={{ margin: '0 8px' }}>&bull;</span>
              <em className="date" style={{ font: 'normal 12px "opensans-regular", sans-serif', background: '#f0f4f5', padding: '3px 10px', borderRadius: '12px', color: '#526066' }}>{cert.graduated}</em>
            </p>
            <p className="text-adjust" style={{ font: '14px/1.6 "opensans-regular", sans-serif', color: '#6E7881', margin: 0 }}>
              {cert.description}
            </p>
          </div>
        )
      })
      var exp = jsonData.exp ? jsonData.exp.map(function(exp){
        return <div name={exp.title} key={exp.title}><h3>{exp.title}</h3>
            <p className="text-adjust">{exp.description}</p>
        </div>
      }) : null;
    }

    return (
      <div>
      <section id="resume">

      <div className="row education">
         <div className="three columns header-col">
            <h1><span>Formação</span></h1>
         </div>

         <div className="nine columns main-col">
            <div className="row item">
               <div className="twelve columns" style={{ borderLeft: '2px solid #e8e8e8', marginLeft: '15px', paddingLeft: '25px' }}>
                 {education}
               </div>
            </div>
         </div>
      </div>

      <div className="row work">

           <div className="three columns header-col">
             <h1><span>EXPERIÊNCIA</span></h1>
           </div>

           <div className="nine columns main-col">
            <div className="row item">
               <div className="twelve columns" style={{ borderLeft: '2px solid #e8e8e8', marginLeft: '15px', paddingLeft: '25px' }}>
                 {work}
               </div>
            </div>
           </div>
      </div>

      <div className="row work">

           <div className="three columns header-col">
             <h1><span>CERTIFICADOS</span></h1>
           </div>

           <div className="nine columns main-col">
            <div className="row item">
               <div className="twelve columns" style={{ borderLeft: '2px solid #e8e8e8', marginLeft: '15px', paddingLeft: '25px' }}>
                 {certification}
               </div>
            </div>
           </div>
      </div>
      <section id="skill">
        <div className="row skill">
          <div className="three columns header-col">
            <h1><span>TECNOLOGIAS</span></h1>
          </div>

            <div className="nine columns main-col">
            {/* {exp} */}
            </div>
        

          {/* <div className="row"> */}
            <div className="three columns header-col">
              <h1><span></span></h1>
            </div>
            <div className="nine columns main-col">
              <p className="text-center hidden">{skillmessage}</p>
                {/* <h3>Conhecimento</h3> */}
                  {tagskills}

                  {/* <div className="bars">
                    <ul className="skills">
                      {skills}
                    </ul>
                  </div> */}
            {/* </div> */}
            {/* <p className="text-center hidden">{skillmessage1}</p> */}
          </div>
        </div>
      </section>
      </section>

    </div>
    );
  }
}

export default Resume;
